"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type StepperContextValue = {
  value: number
  onValueChange?: (value: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

type StepperItemContextValue = {
  step: number
  state: "active" | "completed" | "pending"
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

// ---------------------------------------------------------------------------
// Hooks
// ---------------------------------------------------------------------------

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper>")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem>")
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper
// ---------------------------------------------------------------------------

function Stepper({
  className,
  value,
  onValueChange,
  orientation = "horizontal",
  children,
  ...props
}: React.ComponentProps<"div"> & {
  value: number
  onValueChange?: (value: number) => void
  orientation?: "horizontal" | "vertical"
}) {
  return (
    <StepperContext.Provider value={{ value, onValueChange, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex",
          "data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-start",
          "data-[orientation=vertical]:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

function StepperItem({
  className,
  step,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { value } = useStepper()

  const state: StepperItemContextValue["state"] =
    step < value ? "completed" : step === value ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-step={step}
        className={cn(
          "group/stepper-item flex",
          "group-data-[orientation=horizontal]/stepper:flex-1 group-data-[orientation=horizontal]/stepper:flex-row group-data-[orientation=horizontal]/stepper:items-center",
          "group-data-[orientation=vertical]/stepper:flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      onClick={() => onValueChange?.(step)}
      className={cn(
        "inline-flex shrink-0 items-center gap-2 rounded-md text-left transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium leading-none",
        "data-[state=pending]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      data-orientation={orientation}
      aria-hidden
      className={cn(
        "flex-1 bg-border transition-colors",
        "data-[state=completed]:bg-primary",
        "data-[orientation=horizontal]:h-px data-[orientation=horizontal]:mx-2",
        "data-[orientation=vertical]:ms-4 data-[orientation=vertical]:my-1 data-[orientation=vertical]:w-px data-[orientation=vertical]:self-stretch data-[orientation=vertical]:min-h-4",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperContent
// ---------------------------------------------------------------------------

function StepperContent({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  const { value } = useStepper()
  const { step } = useStepperItem()

  if (step !== value) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

export {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
  useStepper,
}

