"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper>
      <StepperVertical />
      <StepperHorizontal />
    </ExampleWrapper>
  )
}

const STEPS = [
  { step: 1, title: "Account", description: "Create your account" },
  { step: 2, title: "Profile", description: "Set up your profile" },
  { step: 3, title: "Finish", description: "Review and confirm" },
]

function StepperVertical() {
  const [step, setStep] = React.useState(1)

  return (
    <Example title="Vertical">
      <div className="flex w-full max-w-md flex-col gap-8">
        <Stepper value={step} onValueChange={setStep} orientation="vertical">
          {STEPS.map(({ step: s, title, description }, index) => (
            <StepperItem key={s} step={s}>
              <StepperTrigger>
                <span
                  className={[
                    "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
                    "group-data-[state=active]/stepper-item:border-primary group-data-[state=active]/stepper-item:bg-primary group-data-[state=active]/stepper-item:text-primary-foreground",
                    "group-data-[state=completed]/stepper-item:border-primary group-data-[state=completed]/stepper-item:bg-primary group-data-[state=completed]/stepper-item:text-primary-foreground",
                    "group-data-[state=pending]/stepper-item:border-muted-foreground/40 group-data-[state=pending]/stepper-item:text-muted-foreground",
                  ].join(" ")}
                >
                  {s < step ? <CheckIcon className="size-4" /> : s}
                </span>
                <div className="flex flex-col gap-0.5">
                  <StepperTitle>{title}</StepperTitle>
                  <StepperDescription>{description}</StepperDescription>
                </div>
              </StepperTrigger>
              <StepperContent>
                <div className="ms-10 rounded-md border bg-muted/50 p-4 text-sm text-muted-foreground">
                  {s === 1 &&
                    "Enter your email address and choose a password."}
                  {s === 2 && "Add your name, avatar, and other profile details."}
                  {s === 3 &&
                    "Everything looks great! Confirm to create your account."}
                </div>
              </StepperContent>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </Stepper>
        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setStep((s) => Math.max(1, s - 1))}
            disabled={step === 1}
          >
            Back
          </Button>
          <Button
            onClick={() => {
              if (step === STEPS.length) {
                setStep(1)
              } else {
                setStep((s) => Math.min(STEPS.length, s + 1))
              }
            }}
          >
            {step === STEPS.length ? "Finish" : "Continue"}
          </Button>
        </div>
      </div>
    </Example>
  )
}

function StepperHorizontal() {
  const [step, setStep] = React.useState(1)

  return (
    <Example title="Horizontal">
      <div className="flex w-full max-w-lg flex-col gap-8">
        <Stepper value={step} onValueChange={setStep} orientation="horizontal">
          {STEPS.map(({ step: s, title }, index) => (
            <StepperItem key={s} step={s}>
              <StepperTrigger>
                <span
                  className={[
                    "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
                    "group-data-[state=active]/stepper-item:border-primary group-data-[state=active]/stepper-item:bg-primary group-data-[state=active]/stepper-item:text-primary-foreground",
                    "group-data-[state=completed]/stepper-item:border-primary group-data-[state=completed]/stepper-item:bg-primary group-data-[state=completed]/stepper-item:text-primary-foreground",
                    "group-data-[state=pending]/stepper-item:border-muted-foreground/40 group-data-[state=pending]/stepper-item:text-muted-foreground",
                  ].join(" ")}
                >
                  {s < step ? <CheckIcon className="size-4" /> : s}
                </span>
                <StepperTitle>{title}</StepperTitle>
              </StepperTrigger>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </StepperItem>
          ))}
        </Stepper>
        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setStep((s) => Math.max(1, s - 1))}
            disabled={step === 1}
          >
            Back
          </Button>
          <Button
            onClick={() => {
              if (step === STEPS.length) {
                setStep(1)
              } else {
                setStep((s) => Math.min(STEPS.length, s + 1))
              }
            }}
          >
            {step === STEPS.length ? "Finish" : "Continue"}
          </Button>
        </div>
      </div>
    </Example>
  )
}

